  movement_family = 'Carry / trunk / loaded bracing',
  primary_phase_key = 'capacity',
  phase_subrole = 'carry_trunk_loaded_bracing_strength',
  primary_order_slot = 'loaded_carry',
  default_sets = 3,
  default_reps = NULL,
  default_work_seconds = 20,
  default_rest_seconds = 75,
  est_seconds_per_set = 90,
  movement_requirements = '{"primary_joint_actions":["grip","hip_extension","shoulder_depression","trunk_bracing","locomotion"],"primary_tissues":["forearms","core","erectors","upper_back","glutes"],"breathing_demand":"nasal","balance_demand":"stable","impact_level":0,"prerequisites":[],"setup_requirements":["Clear walking lane for loaded carries","Safe pickup and set-down area at both ends","Matched implements for bilateral farmer carry","One-sided implement ready for suitcase carry variants","Safe anterior-load setup for front-rack, bear-hug, and Zercher carries","Safe overhead setup and lowering strategy for overhead carries","Secure cable or band anchor for Pallof and chop work"]}'::jsonb,
  coaching_execution = '{"movement_description":"Pick up matched bilateral loads, stand tall with ribs stacked, walk with controlled steps without swing or lean, set down under control.","setup":["Place two equal loads at the athlete sides.","Hinge or squat to grip safely.","Stand tall before walking.","Shoulders down and slightly back.","Ribs stacked over pelvis."],"execution_steps":["Pick up both weights safely.","Stand tall and brace.","Walk with controlled steps.","Keep weights from swinging.","Maintain even posture.","Set weights down under control."],"breathing_cues":["Breathe behind the brace — avoid breath-holding valsalva at inappropriate loads."],"coach_cues":["Tall posture.","Crush the handles.","Shoulders down.","Walk slow and strong.","No leaning."],"athlete_cues":["Pick up strong.","Stand tall.","Squeeze.","Walk controlled."],"common_faults":["Rounding to pick up weights.","Shoulders shrugging.","Weights swinging.","Rushing steps.","Leaning backward or forward.","Grip fails before safe set-down."],"stop_signs":["Low-back pain.","Grip slipping.","Shoulder pain.","Athlete cannot set weights down safely.","Posture collapses."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Kettlebell Deadlift / Trap-Bar Deadlift","Glute Bridge","Dead Bug","Bracing Prep"],"pairs_well_after":["Suitcase Carry","Front-Rack Carry","Dead Hang / Active Hang","Pallof Press / Pallof Hold"],"good_for_sessions":["capacity_bracing","loaded_carry","trunk_strength"],"avoid_before":["Ninja grip work if farmer carry causes grip fatigue","Max sprinting if heavy carries fatigue posture or legs"],"avoid_after":[],"do_not_use_when":["Grip cannot hold safely","Low-back pain under load","No safe walking lane","Athlete cannot pick up or set down load safely"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["NSCA loaded carry coaching progressions","Farmer carry EMG and multi-plane trunk activation research"],"internal_notes":["Default carry card — validator capacity_carry_posture should flag shrug, swing, and grip slip."]}'::jsonb,
  updated_at = now()
WHERE slug = 'farmer-carry';

UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'loaded_carry',
  order_index = pos.order_index,
  fit_weight = 5,
  freshness_required = FALSE,
  fatigue_sensitivity = 3,
  fatigue_cost = 4,
  technical_complexity = 2,
