UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('farmer-carry', 'Light kettlebell/dumbbell carry, 10–15 yards, posture focus.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
