  ('farmer-carry', 'Light-to-moderate loads; avoid breath-holding/pressure symptoms; shorten distance.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('suitcase-carry', 'Light load, short distance, no breath-holding, symptom-guided.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('front-rack-carry', 'Light load, short distance, no breath-holding or pressure symptoms.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('bear-hug-sandbag-carry', 'Light load, no breath-holding, avoid excessive pressure; symptom-guided.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('zercher-carry', 'Usually prefer light bear-hug/front carry; avoid heavy bracing/pressure.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('overhead-carry', 'Light load; avoid rib flare/pressure symptoms; substitute front carry if needed.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('pallof-press-pallof-hold', 'Excellent when light/moderate and symptom-free; avoid breath-holding and excessive pressure.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('tall-kneeling-cable-band-chop', 'Light resistance; avoid breath-holding and pressure symptoms; use Pallof hold if rotation is uncomfortable.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'pregnancy_postpartum';

INSERT INTO coaching.exercise_scaling_profile (exercise_id, cohort_key, label, scale_direction, load_guidance, gender_specific_notes)
SELECT e.id, 'pregnancy_postpartum', 'pregnancy postpartum', 'baseline', v.guidance,
  CASE WHEN 'pregnancy_postpartum' = 'adult_beginner' THEN v.gender_notes ELSE NULL END
FROM (VALUES
  ('farmer-carry', 'Light-to-moderate loads; avoid breath-holding/pressure symptoms; shorten distance.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('suitcase-carry', 'Light load, short distance, no breath-holding, symptom-guided.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('front-rack-carry', 'Light load, short distance, no breath-holding or pressure symptoms.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('bear-hug-sandbag-carry', 'Light load, no breath-holding, avoid excessive pressure; symptom-guided.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('zercher-carry', 'Usually prefer light bear-hug/front carry; avoid heavy bracing/pressure.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('overhead-carry', 'Light load; avoid rib flare/pressure symptoms; substitute front carry if needed.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('pallof-press-pallof-hold', 'Excellent when light/moderate and symptom-free; avoid breath-holding and excessive pressure.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.'),
  ('tall-kneeling-cable-band-chop', 'Light resistance; avoid breath-holding and pressure symptoms; use Pallof hold if rotation is uncomfortable.', 'No default sex-based adjustment. Scale by movement quality, load tolerance, goals, and symptoms rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
