-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('farmer-carry', 'The farmer carry challenges the athlete to maintain posture while gripping and walking under load. Loaded carries activate core musculature across multiple movement planes while locomoting — building grip capacity, postural strength, upper-back tension, trunk bracing, and total-body organization.', 'Belongs in loaded_carry (451) — default bilateral Capacity carry; broadest carry card across age and skill levels.', 'Primary entry in loaded_carry after Output; default bilateral carry before suitcase, front-rack, or overhead variants when grip and walking posture are still developing.', 'Capacity builds loaded bracing and trunk strength with meaningful load, controlled posture, and full rest — not Prepare activation fluff, Fitness conditioning circuits, or Control isometric holds. Do not use as long-distance conditioning, allow shoulder shrug or grip slip, or prescribe without a clear walking lane and safe set-down.', 'Regress load or distance before reducing posture standard; hypermobility athletes need active shoulder and trunk control — no hanging into joints. Progress load only when every step stays tall and controlled.'),
  ('suitcase-carry', 'The suitcase carry places load on one side of the body, so the trunk must resist lateral flexion while the athlete walks. The core goal is resisting side bend — building anti-lateral-flexion capacity relevant to cutting, landing, and single-leg sport demands.', 'Belongs in anti_lateral_flexion_carry (452) — one-sided Capacity carry after bilateral farmer carry base.', 'anti_lateral_flexion_carry after farmer carry competency; before advanced offset loading when level hips and shoulders stay organized on one side.', 'Capacity builds loaded bracing and trunk strength with meaningful load, controlled posture, and full rest — not Prepare activation fluff, Fitness conditioning circuits, or Control isometric holds. Do not allow lateral lean every step, stack long distances with short rest, or prescribe before farmer carry posture is clean.', 'Regress load or distance before accepting lean; complete prescribed distance per side with full rest. Hypermobility athletes need active rib/pelvis control and shoulder position.'),
  ('front-rack-carry', 'Front-loaded carries require the athlete to resist the weight pulling the torso forward, making them valuable for trunk, upper-back, and posture capacity. The front-rack variation shifts demand anteriorly and requires strong rib/pelvis control and breathing under load.', 'Belongs in front_loaded_carry (453) — anterior Capacity carry after bilateral farmer carry; high trunk and breathing demand.', 'front_loaded_carry after farmer carry base; bridge to front squat and anterior bracing when rack position and rib control are established.', 'Capacity builds loaded bracing and trunk strength with meaningful load, controlled posture, and full rest — not Prepare activation fluff, Fitness conditioning circuits, or Control isometric holds. Do not allow rib flare or lean-back every step, use as conditioning with short rest, or prescribe before rack comfort is established.', 'Regress to goblet or bear-hug carry; progress to double rack only when ribs stay down and elbows stay organized. Hypermobility athletes need active rack — avoid hanging in elbows/wrists.'),
  ('bear-hug-sandbag-carry', 'The bear-hug carry uses an awkward load, which forces the athlete to squeeze, brace, and maintain posture while walking. It develops grip strength, postural endurance, core stability, and bracing mechanics without a technical rack position.', 'Belongs in loaded_carry (451) — awkward-load Capacity carry; useful for trunk, posture, and real-world strength.', 'loaded_carry alongside farmer carry when awkward anterior compression is the priority; before Zercher when bear-hug posture and breathing stay clean.', 'Capacity builds loaded bracing and trunk strength with meaningful load, controlled posture, and full rest — not Prepare activation fluff, Fitness conditioning circuits, or Control isometric holds. Do not let the bag slide or athlete fold forward, use short rest medley conditioning, or pick up with rounded back.', 'Regress bag size or elevate pickup height; progress load only when bag stays high on torso and breathing stays controlled. Hypermobility athletes need active trunk compression.'),
  ('zercher-carry', 'The Zercher load position pulls the athlete forward, so the upper back and trunk must brace hard to maintain posture. The bar rests in the crooks of the elbows and heavily trains thighs, core, upper back, glutes, and trunk stabilizers by keeping the load close to the torso.', 'Belongs in front_loaded_carry (453) — conditional advanced anterior Capacity carry after bear-hug and front-rack competency.', 'front_loaded_carry after bear-hug and front-rack carry competency; conditional advanced anterior carry when load stays close and elbow comfort is managed.', 'Capacity builds loaded bracing and trunk strength with meaningful load, controlled posture, and full rest — not Prepare activation fluff, Fitness conditioning circuits, or Control isometric holds. Do not prescribe before bear-hug/front-rack posture is clean, ignore elbow crease pain, or use as a conditioning medley with short rest.', 'Regress to bear-hug sandbag carry; use pad for elbow comfort; progress load only when load stays close and trunk stays tall. Discontinue on elbow numbness.'),
  ('overhead-carry', 'The overhead carry challenges the athlete to stabilize the shoulder while the trunk resists arching, side-bending, and rotation during walking. It builds overhead posture, shoulder stability, and multi-plane trunk control under load.', 'Belongs in overhead_carry (454) — conditional Capacity carry requiring overhead mobility, shoulder control, and safe load setup.', 'overhead_carry after half-kneeling press and farmer carry competency; conditional when overhead range and rib/pelvis control are pain-free and stable.', 'Capacity builds loaded bracing and trunk strength with meaningful load, controlled posture, and full rest — not Prepare activation fluff, Fitness conditioning circuits, or Control isometric holds. Do not prescribe without overhead mobility, allow rib flare or arm drift, or use as a conditioning walk with short rest.', 'Regress to half-kneeling overhead hold or front-rack carry; single-arm before double; hypermobility athletes need active shoulder position — avoid hanging into lockout.'),
  ('pallof-press-pallof-hold', 'The Pallof press trains anti-rotation: the athlete presses or holds a band/cable away from the body while resisting the pull to twist. It builds trunk stiffness and rib/pelvis control with low impact and easy scaling across stances.', 'Belongs in anti_rotation_strength (455) — default Capacity anti-rotation drill; can be used frequently at low-to-moderate intensity.', 'Primary entry in anti_rotation_strength; daily-ok at low-to-moderate intensity before chop or heavy rotational Output when trunk squareness is the priority.', 'Capacity builds loaded bracing and trunk strength with meaningful load, controlled posture, and full rest — not Prepare activation fluff, Fitness conditioning circuits, or Control isometric holds. Do not allow torso rotation toward anchor, use unsafe band anchor, or load so heavy that hips and shoulders cannot stay square.', 'Regress to Pallof hold or shorter lever; progress stance difficulty only when square hips/shoulders stay clean. Hypermobility athletes need stacked ribs/pelvis — avoid passive leaning.'),
  ('tall-kneeling-cable-band-chop', 'Tall-kneeling chops reduce the athlete''s ability to compensate with the legs, forcing more trunk and hip stability. The chop path trains controlled rotation while demanding quiet hips and organized ribs/pelvis — a bridge between anti-rotation and sport rotation.', 'Belongs in rotational_trunk_strength (456) — controlled Capacity rotation after Pallof anti-rotation base.', 'rotational_trunk_strength after Pallof press competency; when athlete can resist rotation first, then add controlled chop motion with quiet hips.', 'Capacity builds loaded bracing and trunk strength with meaningful load, controlled posture, and full rest — not Prepare activation fluff, Fitness conditioning circuits, or Control isometric holds. Do not allow hip shifting or wild rotation, use unsafe anchor, or prescribe before Pallof squareness is established.', 'Regress to Pallof hold or half-kneeling chop with light band; shorten range before adding load. Hypermobility athletes need controlled rib/pelvis position — avoid excessive spine rotation.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Carry / loaded-bracing Capacity cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'capacity_carry_readiness',
  NULL,
  'Carry / Trunk / Loaded-Bracing Capacity without stealing skill quality',
  'Loaded-bracing Capacity needs meaningful load, strong posture, controlled breathing, and full rest — not long-distance conditioning or ugly posture survival.',
  'Carry cluster: farmer carry, suitcase carry, front-rack carry, bear-hug sandbag carry, Zercher carry, overhead carry, Pallof press/hold, and tall-kneeling cable/band chop.',
  'Loaded carries and anti-rotation work build trunk stiffness, grip, posture, and breathing under load for sprinting, tumbling, ninja, and general strength. Poor placement or posture collapse raises injury risk and reduces skill quality.',
  'Place after Output unless strength-priority; master farmer/suitcase before overhead and Zercher; regress on lean, rib flare, or grip failure; keep carry distance moderate with full rest — not long circuits.',
  'Do not program long carry circuits before tumbling or sprint skill, use overhead carry without mobility, or finish sets with collapsed posture for Capacity intent.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
